create table dirkspzm32.pzm_log (
    log_id            number(12, 0) default dirkspzm32.seq_pzm_log_id.nextval not null enable,
    log_timestamp     timestamp(3) default systimestamp not null enable,
    log_level         number(1, 0) not null enable,
    log_category      varchar2(50 char) not null enable,
    log_module        varchar2(100 char),
    log_message       varchar2(4000 char) not null enable,
    log_error_code    number(*, 0),
    log_stacktrace    varchar2(4000 char),
    pers_nr           number(*, 0),
    ze_rfid           varchar2(50 char),
    ze_id             number(*, 0),
    schicht_tag       date,
    terminal_id       varchar2(50 char),
    aktion            varchar2(50 char),
    quelle            varchar2(50 char),
    os_user           varchar2(30 char),
    client_host       varchar2(100 char),
    client_info       varchar2(100 char),
    client_identifier varchar2(100 char)
);

alter table dirkspzm32.pzm_log
    add constraint chk_pzm_log_level check ( log_level between 0 and 5 ) enable;

alter table dirkspzm32.pzm_log
    add constraint pk_pzm_log primary key ( log_id )
        using index enable;


